arguments.new_str:
using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Keep "Discriminator" property name so existing documents remain readable.
        // EF Core 9 changed the default from "Discriminator" to "$type".
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Keep the old compound id format ("Blog|1") so existing documents
        // remain accessible. EF Core 9 changed to key-only ids by default.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // REMOVED: .HasIndex(b => b.Name)
        // EF Core 9 Cosmos provider now throws on HasIndex — Cosmos DB indexing
        // is managed via the container's indexing policy (Azure Portal / Bicep).
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

arguments.old_str:
class SyncJob
{
    void Run(BlogContext context)
    {
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }
}

arguments.new_str:
class SyncJob
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O.
    // ToList() and SaveChanges() must become async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

